    public static final int LOONCODE_APO_SUPP = 434;

    private static final int EXTENSIE_APO = 999;

    private static final int RSZPPO_LOONCODE_APO_FISK_FICHE_281_12 = 121;
    private static final int DMFAPPL_LOONCODE_APO_FISK_FICHE_281_12 = 101;

    private static final int LOONCODE_APO_KOL30_GEW_MNDLN = 212;

    private static final int RSZPPO_LOONCODE_APO_KOL12_WISS = 511;
    private static final int DMFAPPL_LOONCODE_APO_KOL12_WISS = 910;

    private static final int LOONCODE_APO_KOL13_HASTA = 421;

    private static final int LOONCODE_APO_KOL14_DIPL = 422;

    private static final int LOONCODE_APO_KOL17_WAPLA = 424;

    private static final int RSZPPO_LOONCODE_APO_KOL20_VAKGELD = 412;
    private static final int DMFAPPL_LOONCODE_APO_KOL20_VAKGELD = 312;

    private static final int RSZPPO_LOONCODE_APO_KOL21_VAKGELDUD = 413;
    private static final int DMFAPPL_LOONCODE_APO_KOL21_VAKGELDUD = 313;

    private static final int LOONCODE_APO_KOL22_EJT = 417;

    private static final int LOONCODE_APO_SUPP_V = 834;

    private static final Set<Pensioenstelsel> HEEFT_BIJDRAGE_PENSIOEN_GEWOON = Sets.immutableEnumSet(
            Pensioenstelsel.NVT_NIET_VASTBENOEMD,
            Pensioenstelsel.RSZPPO,
            Pensioenstelsel.RSZPPO_AFWIJKING1,
            Pensioenstelsel.NVT_GEEN_KATEGORIE);

    private static final String OPDRACHT_FETCH_STRING = "opperSlices{rszppo, weddeBerekening, boekhouding, opdrachtFiscaliteit,"
            + "basisJaarWedde, vergoedingSet{vergoedingen}, pensioenEnMandataris}";

    private static final Map<FiskFiche, LnedefRegBv> FICHE_TO_REGIME_MAP;

    static {
        ImmutableMap.Builder<FiskFiche, LnedefRegBv> builder = ImmutableMap.builder();
        builder.put(FiskFiche.FISK_FICHE_281_10, LnedefRegBv.VD_BV_10_BZ___GB);
        builder.put(FiskFiche.FISK_FICHE_281_11, LnedefRegBv.VD_BV_11_PENS_GB);
        builder.put(FiskFiche.FISK_FICHE_281_12, LnedefRegBv.VD_BV_12_VVI__NBV);
        builder.put(FiskFiche.FISK_FICHE_281_14, LnedefRegBv.VD_BV_14_B_AU_EXC);
        builder.put(FiskFiche.FISK_FICHE_281_14_TAO, LnedefRegBv.VD_BV_14_TAO);
        builder.put(FiskFiche.FISK_FICHE_281_16, LnedefRegBv.VD_BV_16_RENTE_EXC);
        builder.put(FiskFiche.FISK_FICHE_281_18, LnedefRegBv.VD_BV_10_UKZI_GB);
        FICHE_TO_REGIME_MAP = builder.build();
    }

    private static final Set<Integer> CODES_GEWOON_LOON = ImmutableSet.of(101, 120, 212, 501, 502, 521, 921, 1001, 1011);

    @Autowired
    private AchterstalPreOmschakelingService achterstalPreOmschakelingService;

    @Autowired
    private OpdrachtService opdrachtService;

