    private ApoInputService apoInputService;

    public void converteer(Admin admin, LocalDate beginDatum, LocalDate eindDatum) {
        List<AchterstalPreOmschakeling> apoGegevens = achterstalPreOmschakelingService.findByPeriode(admin, beginDatum, eindDatum);

        for (AchterstalPreOmschakeling apoGegeven : apoGegevens) {
            log.trace("ApoConversie PersoonId: {}, OpdrachtNr: {}, BeginDatum: {}", apoGegeven.getPersoon().getId(), apoGegeven.getOpdrachtNummer(),
                    apoGegeven.getBeginDatum());

            try {
                converteerApo(admin, apoGegeven);
            } catch (Exception e) {
                throw new RuntimeException(
                        "Fout bij APO-conversie van persoonId: " + apoGegeven.getPersoon().getId() + ", opdrachtNr: " + apoGegeven.getOpdrachtNummer()
                                + ", beginDatum: " + apoGegeven.getBeginDatum(), e);
            }
        }
    }

    private void converteerApo(Admin admin, AchterstalPreOmschakeling apoGegeven) {
        TemporalContext.getInstance().setActualInterval(new LocalDateInterval(apoGegeven.getBeginDatum(), apoGegeven.getEindDatum()));
        Opdracht opdracht =
                opdrachtService.getByPersoonOpdrachtNr(admin, apoGegeven.getPersoon().getId(), apoGegeven.getOpdrachtNummer(), OPDRACHT_FETCH_STRING);
        TemporalContext.getInstance().clearActualInterval();

        if (opdracht == null) {
            log.info("Geen opdracht gevonden voor deze APO bij Conversie:  PersoonId: {}, OpdrachtNr: {}, BeginDatum: {}", apoGegeven.getPersoon().getId(), apoGegeven
                    .getOpdrachtNummer(), apoGegeven.getBeginDatum());
            return;
        }

        AkeTijdperk tijdperk = RekenTools.getTijdperk(new Month(apoGegeven.getBeginDatum()));

        Set<LoonElement> loonElementen = LoonElement.createSortedSet();

        int codeGewoonLoon = getCodeGewoonLoon(tijdperk, opdracht, apoGegeven);

        vormLoonElement(loonElementen, getLoonCode(tijdperk, codeGewoonLoon), apoGegeven.getBrutoMaandWedde());
        vormLoonElement(loonElementen, getLoonCode(tijdperk, getCodeWisseldienst(tijdperk)), apoGegeven.getWisseldienst());
        vormLoonElement(loonElementen, getLoonCode(tijdperk, LOONCODE_APO_KOL13_HASTA), apoGegeven.getHasta());
        vormLoonElement(loonElementen, getLoonCode(tijdperk, LOONCODE_APO_KOL14_DIPL), apoGegeven.getDiplomaBijslag());
        vormLoonElement(loonElementen, getLoonCode(tijdperk, LOONCODE_APO_KOL17_WAPLA), apoGegeven.getVergoedingHogereFunctie());
        vormLoonElement(loonElementen, getLoonCode(tijdperk, getCodeDubbelVakantieGeld(tijdperk)), apoGegeven.getDubbelVakantiegeld());
        vormLoonElement(loonElementen, getLoonCode(tijdperk, getCodeEnkelVakantieGeldUitdiensttreding(tijdperk)),
                apoGegeven.getEnkelVakgeldUitdiensttreding());
        vormLoonElement(loonElementen, getLoonCode(tijdperk, LOONCODE_APO_KOL22_EJT), apoGegeven.getEindejaarsToelage());
        vormLoonElement(loonElementen, getLoonCode(tijdperk, LOONCODE_APO_KOL30_GEW_MNDLN), apoGegeven.getGewaarborgdLoon());
        vormLoonElement(loonElementen, getLoonCode(tijdperk, LOONCODE_APO_SUPP_V), apoGegeven.getAndereToelagenVastbenoemden());

        Money brutoAndereToelagen = apoGegeven.getAndereToelagen().add(apoGegeven.getAndereToelagenNsi()).add(apoGegeven.getAndereToelagenNsiNbb());
        Money bassiAndereToelagen = apoGegeven.getAndereToelagen();
        vormLoonElement(loonElementen, getLoonCode(tijdperk, LOONCODE_APO_SUPP), brutoAndereToelagen, bassiAndereToelagen,
                apoGegeven.getAndereToelagenNsiNbb());

        vormLoonElementenInhoudingen(loonElementen, apoGegeven);

        vormDefaultLoonElement(loonElementen, getLoonCode(tijdperk, codeGewoonLoon));
        Money bassiTotaal = getBassiTotaal(apoGegeven);

        verdeelRszBijdrage(opdracht, apoGegeven, bassiTotaal, loonElementen);

        ApoHoofd hoofd = maakApoInput(opdracht, apoGegeven, codeGewoonLoon, loonElementen);

        apoInputService.create(admin, hoofd);
    }

    private void verdeelRszBijdrage(Opdracht opdracht, AchterstalPreOmschakeling apoGegeven, Money bassiTotaal, Set<LoonElement> loonElementen) {
        Hoedanigheid hoedanigheid = opdracht.getHoedanigheid();
        RekenRszKey rszBijdrageKey;
        RekenPatronaalRszKey patronaleRszKey = null;
        RekenRszKey pensBijdrageKey = null;
        RekenPatronaalRszKey patronalePensKey = null;
        RekenRszKey bijzBijdrageKey = null;
        switch (hoedanigheid) {
            case MANDATARISSEN:
                rszBijdrageKey = RekenRszKey.BIJDRAGE_RSZ_KEY;
                pensBijdrageKey = RekenRszKey.BIJDRAGE_PENSIOEN_MANDATARIS_KEY;
                break;
            case MANDATARISSEN_GEPENSIOENEERD:
            case WERKNEMERS_GEPENSIOENEERD:
                rszBijdrageKey = RekenRszKey.BIJDRAGE_ZIV_GEPENSIONEERD_KEY;
                pensBijdrageKey = RekenRszKey.BIJDRAGE_GEPENSIOENEERD_BEGRAFENIS_KEY;
                bijzBijdrageKey = RekenRszKey.SOLIDARITEITS_BIJDRAGE_PENSIOEN_KEY;
                break;
            default:
                rszBijdrageKey = RekenRszKey.BIJDRAGE_RSZ_KEY;
                patronaleRszKey = RekenPatronaalRszKey.PATRONALE_BIJDRAGE_RSZ_KEY;
                bijzBijdrageKey = RekenRszKey.BIJZONDERE_BIJDRAGE_KEY;
                TypePensioenBijdrage type = getBijdragePensioenVastbenoemdenKey(apoGegeven);
                if (type == TypePensioenBijdrage.GEWOON) {
                    pensBijdrageKey = RekenRszKey.BIJDRAGE_PENSIOEN_VASTBENOEMDEN_KEY;
                    patronalePensKey = RekenPatronaalRszKey.PATRONALE_BIJDRAGE_PENSIOEN_VASTBENOEMDEN_KEY;
                } else if (type == TypePensioenBijdrage.APK) {
                    pensBijdrageKey = RekenRszKey.BIJDRAGE_PENSIOEN_VASTBENOEMDEN_APK_KEY;
                    patronalePensKey = RekenPatronaalRszKey.PATRONALE_BIJDRAGE_PENSIOEN_VASTBENOEMDEN_APK_KEY;

                }
                break;
        }

        verdeelBedragVolgensBasisChecked(rszBijdrageKey, apoGegeven.getInhoudingRszZiv(), RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY, bassiTotaal,
                loonElementen);

        if (patronaleRszKey != null) {
            verdeelBedragVolgensBasisChecked(patronaleRszKey, apoGegeven.getInhoudingPatronaleRszZiv(), RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY,
                    bassiTotaal, loonElementen);
        }

        if (pensBijdrageKey != null) {
            verdeelBedragVolgensBasisChecked(pensBijdrageKey, apoGegeven.getInhoudingPensioen(), RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY,
                    bassiTotaal, loonElementen);
        }
        if (patronalePensKey != null) {
            verdeelBedragVolgensBasisChecked(patronalePensKey, apoGegeven.getInhoudingPatronalePensioen(),
                    RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY, bassiTotaal, loonElementen);
        }

        if (bijzBijdrageKey != null) {
            verdeelBedragVolgensBasisChecked(bijzBijdrageKey, apoGegeven.getInhoudingBijzonderBijdrage(), RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY,
                    bassiTotaal, loonElementen);
        }
    }

    private void verdeelBedragVolgensBasisChecked(
            MoneyKey bedragKey, Money totaalBedrag, MoneyKey basisKey, Money totaalBasis,
            Set<LoonElement> loonElementen) {
        if (totaalBasis.signum() != 0) {
            BedragVerdelerFactory.verdeelBedragVolgensBasisPut(bedragKey, totaalBedrag, basisKey, totaalBasis, loonElementen);
        } else {
            EvenredigeVerdelerFactory.verdeelEvenredigPut(bedragKey, totaalBedrag, loonElementen);
        }
    }

    private enum TypePensioenBijdrage {
        GEWOON,
        APK,
        GEEN
    }

    private TypePensioenBijdrage getBijdragePensioenVastbenoemdenKey(AchterstalPreOmschakeling apoGegeven) {
        if (HEEFT_BIJDRAGE_PENSIOEN_GEWOON.contains(apoGegeven.getPensioenStelsel())) {
            return TypePensioenBijdrage.GEWOON;
        } else {
            return TypePensioenBijdrage.APK;
        }
    }

    private ApoHoofd maakApoInput(Opdracht opdracht, AchterstalPreOmschakeling apoGegeven, int codeGewoonLoon, Set<LoonElement> loonElementen) {
        ApoHoofd hoofd = maakApoHoofd(opdracht, apoGegeven);
        Set<ApoLijn> lijnen = ApoLijnComparator.createSortedSet();
        for (LoonElement element : loonElementen) {
            AardKodeExtensie loonCode = element.getAardKodeExtensie();
            LnedefRegBv regime = bepaalRegimeApo(apoGegeven, loonCode);
            ApoLijn lijn = maakApoLijn(hoofd, loonCode, regime);
            Set<ApoBedrag> apoBedragen = vormApoBedragen(element, lijn);
            lijn.setApoBedragen(apoBedragen);
            lijnen.add(lijn);
        }
        hoofd.setApoLijnen(lijnen);
        return hoofd;
    }

    public static LnedefRegBv bepaalRegimeApo(AchterstalPreOmschakeling apoGegeven, AardKodeExtensie loonCode) {
        LnedefRegBv regime;
        if (loonCode.getAard().equals(AardKodeExt.I_KODE_EXT.getCode())) {
            regime = loonCode.getRegimeBv();
        } else {
            regime = FICHE_TO_REGIME_MAP.getOrDefault(apoGegeven.getFiscaleFiche(), loonCode.getRegimeBv());
        }
        return regime;
    }

    public static LnedefRegBv bepaalRegimeApo(List<AchterstalPreOmschakeling> apoGegeven, AardKodeExtensie loonCode) {

        Predicate<AchterstalPreOmschakeling> predicate = x -> true;
        if (CODES_GEWOON_LOON.contains(loonCode.getCode())) {
            predicate = x -> x.getBrutoMaandWedde().signum() != 0;
        }
        if (loonCode.getCode() == RSZPPO_LOONCODE_APO_KOL12_WISS || loonCode.getCode() == DMFAPPL_LOONCODE_APO_KOL12_WISS) {
            predicate = x -> x.getWisseldienst().signum() != 0;
        } else if (loonCode.getCode() == LOONCODE_APO_KOL13_HASTA) {
            predicate = x -> x.getHasta().signum() != 0;
        } else if (loonCode.getCode() == LOONCODE_APO_KOL14_DIPL) {
            predicate = x -> x.getDiplomaBijslag().signum() != 0;
        } else if (loonCode.getCode() == LOONCODE_APO_KOL17_WAPLA) {
            predicate = x -> x.getVergoedingHogereFunctie().signum() != 0;
        } else if (loonCode.getCode() == LOONCODE_APO_KOL17_WAPLA) {
            predicate = x -> x.getVergoedingHogereFunctie().signum() != 0;
        } else if (loonCode.getCode() == RSZPPO_LOONCODE_APO_KOL20_VAKGELD || loonCode.getCode() == DMFAPPL_LOONCODE_APO_KOL20_VAKGELD) {
            predicate = x -> x.getDubbelVakantiegeld().signum() != 0;
        } else if (loonCode.getCode() == RSZPPO_LOONCODE_APO_KOL21_VAKGELDUD || loonCode.getCode() == DMFAPPL_LOONCODE_APO_KOL21_VAKGELDUD) {
            predicate = x -> x.getEnkelVakgeldUitdiensttreding().signum() != 0;
        } else if (loonCode.getCode() == LOONCODE_APO_KOL22_EJT) {
            predicate = x -> x.getEindejaarsToelage().signum() != 0;
        } else if (loonCode.getCode() == LOONCODE_APO_KOL30_GEW_MNDLN) {
            predicate = x -> x.getGewaarborgdLoon().signum() != 0;
        } else if (loonCode.getCode() == LOONCODE_APO_SUPP_V) {
            predicate = x -> x.getAndereToelagenVastbenoemden().signum() != 0;
        } else if (loonCode.getCode() == LOONCODE_APO_SUPP) {
            predicate =
                    x -> x.getAndereToelagen().signum() != 0 || x.getAndereToelagenNsi().signum() != 0 || x.getAndereToelagenNsiNbb().signum() != 0;
        }
        AchterstalPreOmschakeling found = apoGegeven.stream().filter(predicate).findFirst().orElse(null);
        LnedefRegBv regime;
        if (found == null && !apoGegeven.isEmpty()) {
            found = apoGegeven.get(0);
        }
        if (found == null) {
            regime = loonCode.getRegimeBv();
        } else {
            regime = FICHE_TO_REGIME_MAP.getOrDefault(found.getFiscaleFiche(), loonCode.getRegimeBv());
        }
        return regime;
    }

    private Set<ApoBedrag> vormApoBedragen(LoonElement element, ApoLijn lijn) {
        Set<ApoBedrag> apoBedragen = ApoBedragComparator.createSortedSet();
        for (Entry<ContextKey, Object> entry : element.getProperties().entrySet()) {
            if (entry.getKey() instanceof MoneyKey && entry.getKey().isTeBewaren()) {
                ApoBedrag apoBedrag = maakApoBedrag((MoneyKey) entry.getKey(), (Money) entry.getValue(), lijn);
                apoBedragen.add(apoBedrag);
            }
        }
        return apoBedragen;
    }

    private Money getBassiTotaal(AchterstalPreOmschakeling apoGegeven) {
        Money bassiTotaal = Money.ZERO;
        bassiTotaal = bassiTotaal.add(apoGegeven.getBrutoMaandWedde());
        bassiTotaal = bassiTotaal.add(apoGegeven.getWisseldienst());
        bassiTotaal = bassiTotaal.add(apoGegeven.getHasta());
        bassiTotaal = bassiTotaal.add(apoGegeven.getDiplomaBijslag());
        bassiTotaal = bassiTotaal.add(apoGegeven.getVergoedingHogereFunctie());
        bassiTotaal = bassiTotaal.add(apoGegeven.getDubbelVakantiegeld());
        bassiTotaal = bassiTotaal.add(apoGegeven.getEnkelVakgeldUitdiensttreding());
        bassiTotaal = bassiTotaal.add(apoGegeven.getEindejaarsToelage());
        bassiTotaal = bassiTotaal.add(apoGegeven.getGewaarborgdLoon());
        bassiTotaal = bassiTotaal.add(apoGegeven.getAndereToelagenVastbenoemden());
        bassiTotaal = bassiTotaal.add(apoGegeven.getAndereToelagen());
        return bassiTotaal;
    }

    private AardKodeExtensie getLoonCode(AkeTijdperk tijdperk, int code) {
        return aardKodeExtensieFacade.getAkeByTijdperkAardCodeExtensie(tijdperk.getCode(), AardKodeExt.S_KODE_EXT.getCode(), code, EXTENSIE_APO);
    }

    private int getCodeGewoonLoon(AkeTijdperk tijdperk, Opdracht opdracht, AchterstalPreOmschakeling apoGegeven) {
        RekenTijd rekenTijd = new RekenTijd(new Month(apoGegeven.getBeginDatum()), null, null, null, null, false, true);
        RegulManager regulManager = new MockRegulManager();
        LoonCodeManager loonCodeManager = new LoonCodeManagerImp(regulManager, aardKodeExtensieFacade);
        GewoonLoon gewoonLoon = GewoonLoonFactory.getGewoonLoon(loonCodeManager, rekenTijd);
        Integer code;
        if (apoGegeven.getFiscaleFiche() == FiskFiche.FISK_FICHE_281_12) {
            code = getCodeFiskFiche281p12(tijdperk);
        } else {
            Opper opper = RekenTools.getOpperLaatsteGegevens(opdracht);
            SleutelGegevens gegevens = new SleutelGegevensSingleOpper(opper);
            if (tijdperk == AkeTijdperk.RSZPPO) {
                code = gewoonLoon.bepaalAardKodeExtensieGewoonLoonRszppo(apoGegeven.getCategorie(), opdracht.getHoedanigheid(), gegevens.getRekenWijze())
                        .getCode();
            } else {
                CategorieKengetal categorieKengetal =
                        CategorieKengetalFactory.getCategorieKengetal(rekenTijd.beginDatum, apoGegeven.getWerkgeversCategorie(), apoGegeven.getWerknemersKengetal());
                CategorieKengetalStatuut categorieKengetalStatuut = CategorieKengetalStatuutFactory.getCategorieKengetalStatuut(rekenTijd,
                        categorieKengetal, gegevens.getStatuutDmfappl());
                CategorieKengetalStatuutPensioenstelsel categorieKengetalStatuutPensioenstelsel =
                        CategorieKengetalStatuutPensioenstelselFactory.create(rekenTijd, categorieKengetalStatuut, gegevens.getPensioenStelsel());

                Integer opproefbenoemd = opdracht.getOpdrachtAanvullendeGegevens().getOpproefbenoemd();
                BepaalAardCodeExtensieData data = BepaalAardCodeExtensieData.builder()
                        .afwezigheidsCode(gegevens.getAfwezigheidsCode())
                        .categorieKengetalStatuutPensioenstelsel(categorieKengetalStatuutPensioenstelsel)
                        .hoedanigheid(opdracht.getHoedanigheid())
                        .mra1(gegevens.getMaatregelingReorganisatieArbeidsTijd())
                        .mra2(gegevens.getMaatregelingReorganisatieArbeidsTijd2())
                        .opProefBenoemd(Nvtjaneen.getByCode(opproefbenoemd))
                        .rekenwijze(gegevens.getRekenWijze())
                        .build();

                code = gewoonLoon.bepaalAardKodeExtensieGewoonLoonDmfappl(data).getCode();
            }
        }
        return code;
    }

