    private void vormLoonElement(Set<LoonElement> loonElementen, AardKodeExtensie loonCode, Money brutoBedrag) {
        vormLoonElement(loonElementen, loonCode, brutoBedrag, brutoBedrag, Money.ZERO);
    }

    private void vormDefaultLoonElement(Set<LoonElement> loonElementen, AardKodeExtensie loonCode) {
        if (loonElementen.isEmpty()) {
            LoonElement element = new LoonElement(loonCode);
            loonElementen.add(element);
        }
    }

    private void vormLoonElement(Set<LoonElement> loonElementen, AardKodeExtensie loonCode, Money bruto, Money bassi, Money negatiefBelastbaar) {
        if (bruto.signum() != 0 || bassi.signum() != 0) {
            LoonElement element = new LoonElement(loonCode);
            element.putProperty(RekenBrutoKey.BRUTO_MAANDLOON_KEY, bruto);
            element.putProperty(RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY, bassi);
            if (negatiefBelastbaar.signum() != 0) {
                element.putProperty(RekenBbKey.NIET_BELASTBAAR_APO_KEY, negatiefBelastbaar);
            }
            loonElementen.add(element);
        }
    }

    private void vormLoonElementenInhoudingen(Set<LoonElement> loonElementen, AchterstalPreOmschakeling apoGegeven) {
        for (int index = 0; index < AchterstalPreOmschakeling.AANTAL_INHOUDINGEN; index++) {
            Integer tijdperk = apoGegeven.getInhoudingTijdperk();
            Integer code = apoGegeven.getInhoudingCode(index);
            Integer extensie = apoGegeven.getInhoudingExtensie(index);
            Money inhouding = apoGegeven.getInhoudingBedrag(index).negate();
            if (code != 0 && inhouding.signum() != 0) {
                AardKodeExtensie loonCode =
                        aardKodeExtensieFacade.getAkeByTijdperkAardCodeExtensie(tijdperk, AardKodeExt.I_KODE_EXT.getCode(), code, extensie);
                LoonElement element = new LoonElement(loonCode);
                element.putProperty(RekenNettoKey.NETTO_KEY, inhouding);
                loonElementen.add(element);
            }
        }
    }

    private ApoHoofd maakApoHoofd(Opdracht opdracht, AchterstalPreOmschakeling apoGegeven) {
        ApoHoofd hoofd = new ApoHoofdPO();
        hoofd.setBeginDatum(apoGegeven.getBeginDatum().withDayOfMonth(1));
        hoofd.setEindDatum(apoGegeven.getEindDatum().dayOfMonth().withMaximumValue());
        hoofd.setOpdracht(opdracht);
        hoofd.setIngaveTijdstip(apoGegeven.getIngaveTijdstip());
        hoofd.setRegulTijdstip(apoGegeven.getRegultijdstip());
        hoofd.setApoLijnen(new HashSet<>());
        hoofd.setBron(ApoHoofdBron.CONVERSIE);
        return hoofd;
    }

    private ApoLijn maakApoLijn(ApoHoofd hoofd, AardKodeExtensie loonCode, LnedefRegBv regime) {
        ApoLijn lijn = new ApoLijnPO();
        lijn.setIngaveTijdstip(hoofd.getIngaveTijdstip());
        lijn.setRegulTijdstip(hoofd.getRegulTijdstip());
        lijn.setAardKodeExtensie(loonCode);
        lijn.setApoHoofd(hoofd);
        lijn.setApoBedragen(new HashSet<>());
        lijn.setRegimeBv(regime);
        return lijn;
    }

    private ApoBedrag maakApoBedrag(MoneyKey key, Money bedrag, ApoLijn lijn) {
        ApoBedrag apoBedrag = new ApoBedragPO();
        apoBedrag.setIngaveTijdstip(lijn.getIngaveTijdstip());
        apoBedrag.setRegulTijdstip(lijn.getRegulTijdstip());
        apoBedrag.setBedragType(RekenTools.moneyKeyToBedragType(key));
        apoBedrag.setBedrag(bedrag);
        return apoBedrag;
    }
